select 
from llm_model_config


        and (model_code like #{keywordLike}
        or model_name like #{keywordLike}
        or provider like #{keywordLike}
        or model_identifier like #{keywordLike})


        and provider = #{query.provider}


        and status = #{query.status}


order by default_model desc, updated_at desc
